#include <stdio.h>

int main() {
    int n, k;
    scanf("%d %d", &n, &k);

    int summ = 0;
    int index = 0;
    for (int i = 1; i <= n; i++) {
        summ += i;
        int candy = summ - (n - i);
        if (candy == k) {
            index = i;
            break;
        }
    }
    printf("%d", n - index);
    return 0;
}
